#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
            A[i]--;
        }
        int* visited = (int*)malloc(N * sizeof(int));
        for(int i = 0; i < N; i++) visited[i] = 0;
        int result = 1;
        for (int i = 0; i < N; i++) {
            if (!visited[i]) {
                int cycleLength = 0;
                int j = i;
                while (!visited[j]) {
                    visited[j] = 1;
                    j = A[j];
                    cycleLength++;
                }
                result = (long long)lcm(result, cycleLength) % MOD;
            }
        }
        printf("%d\n", result);
        free(A);
        free(visited);
    }
    return 0;
}

