        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt() - 1;
            }
            boolean[] visited = new boolean[N];
            int result = 1;
            for (int i = 0; i < N; i++) {
                if (!visited[i]) {
                    int cycleLength = 0;
                    int j = i;
                    while (!visited[j]) {
                        visited[j] = true;
                        j = A[j];
                        cycleLength++;
                    }
                    result = (int)((long)lcm(result, cycleLength) % 1000000007);
                }
            }
            System.out.println(result);
        }
    }
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static int lcm(int a, int b) {
        return (a * b) / gcd(a, b);
